import discord
from discord.ext import commands
import os
from dotenv import load_dotenv

load_dotenv()

class MyBot(commands.Bot):
    def __init__(self):
        intents = discord.Intents.default()
        intents.members = True # ユーザー名やアイコン取得に必要
        intents.message_content = True
        super().__init__(command_prefix='!', intents=intents)

    async def setup_hook(self):
        # cogsフォルダ内のファイルを読み込む
        for filename in os.listdir('./cogs'):
            if filename.endswith('.py'):
                await self.load_extension(f'cogs.{filename[:-3]}')

        # スラッシュコマンドをDiscordに同期する
        await self.tree.sync()

    async def on_ready(self):
        print(f'ログインしました: {self.user.name}')

        # --- 追加: Webデータの初期生成 ---
        economy_cog = self.get_cog('Economy')
        if economy_cog:
            # 起動直後はDiscordの準備が完全に整っていない場合があるため
            # 少し待ってから実行するか、そのまま実行します
            success = economy_cog.update_web_data()
            if success:
                print('Webサイト用のデータを正常に生成しました。')
            else:
                print('Webデータの生成に失敗しました。')
        # ------------------------------

bot = MyBot()
TOKEN = os.getenv('DISCORD_TOKEN')
bot.run(TOKEN)
